import { DatePipe } from "@angular/common";
import { ChangeDetectorRef, Component } from "@angular/core";
import { FormArray, FormBuilder, FormGroup } from "@angular/forms";
import { Preferences } from "@capacitor/preferences";
import { AlertService } from "src/app/core/services/alert.service";
import { BankService } from "src/app/core/services/bank.service";
import { InputMaskingService } from "src/app/core/services/input-masking.service";
import { InstallmentsService } from "src/app/core/services/installments.service";
import { LoansService } from "src/app/core/services/loans.service";
import { ReferencesService } from "src/app/core/services/references.service";
import { UserService } from "src/app/core/services/user.service";
import { DatepickerOptions } from "src/app/views/components/ngx-datepicker/datepicker.component";
import { RescheduleBanks } from "src/app/views/Models/Banks/RescheduleBanks";
import { InstallmentsInfo } from "src/app/views/Models/Installments/InstallmentsInfo";
import { LoanInfoData } from "src/app/views/Models/Loan/LoanInfoData";
import { RescheduleLoanRequest } from "src/app/views/Models/Loan/RescheduleLoanRequest";
import { SearchResult } from "src/app/views/Models/References/SearchResult";
import { StaticRef } from "src/app/views/Models/References/StaticRef";
import { UserBranchInfo } from "src/app/views/Models/Users/User";
import * as customValidators from "src/app/core/validators/custom-validators";
import { HttpClient } from "@angular/common/http";
import { EnvService } from "src/app/core/services/env.service";
import { ReportingService } from "src/app/core/services/reporting.service";
import { MohassilAuthService } from "src/app/core/services/AuthenticationServices/mohassil-auth.service";
import { PdfViewerService } from "src/app/core/services/pdf-viewer.service";
import { AccessRight } from "src/app/views/Models/Permissions/AccessRight";
import { atobSafe } from "src/app/core/util/atobSafe";

@Component({
  selector: "app-loan-reschedule",
  templateUrl: "./loan-reschedule.page.html",
  styleUrls: ["./loan-reschedule.page.scss"],
  providers: [DatePipe],
})
export class LoanReschedulePage {
  //#region Flags
  showLoader: boolean = false;
  isSearching: boolean = true;
  loanGridView: boolean = false;
  RescheduleView: boolean = false;
  instIntCheckboxDisable: boolean = false;
  gracePrdInstCheckboxDisable: boolean = true;
  instIntCheckbox: boolean = false;
  gracePrdInstCheckbox: boolean = false;
  rescheduleOptionDisable: boolean = false;
  TransDateDisabled: boolean = false;
  checkDatesInput: boolean = false;
  checkInstMatDateInput: boolean = false;
  FreeRescheduleAccess: boolean = false;
  FreeReschedule: boolean = false;
  ChequesPrintCheckbox: boolean = false;
  //#endregion
  //#region Variables
  pageTypeAccessRights: AccessRight[];
  accordionGroupValue: string = "first";
  initialSearchType: string = "1";
  ClientloanList: LoanInfoData[] = null;
  selectedLoan: LoanInfoData = null;
  installmentsInfo: InstallmentsInfo[] = null;
  rescheduleOptions: StaticRef[];
  rescheduleRequest: RescheduleLoanRequest = null;
  nullDate: Date = new Date("1900-01-01");
  todayDate: Date = new Date();
  periodStartDate: Date;
  periodEndDate: Date;
  calcFeesFrom: number = 0;
  newInstallmentsInfo: InstallmentsInfo[] = null;
  rescheduleBanks: RescheduleBanks[] = null;
  loanNo: number = null;
  loanIntRt: number = null;
  FixedLoanNo: number = null;
  FixedloanIntRt: number = null;
  FixedFirstIntDate: string = null;
  FixedTransDate: string = null;
  FixedGracePeriod: number = null;
  gracePeriod: number = 0;
  TransDatePickerOptions: DatepickerOptions;
  FirstInstDatePickerOptions: DatepickerOptions;
  userBranchInfo: UserBranchInfo;
  prevLoanNo: number = null;
  prevGracePeriod: number = null;
  prevLoanIntRt: number = null;
  prevTransDate: Date = null;
  prevFirstInstDate: Date = null;
  //#endregion
  //#region Forms
  rescheduleForm: FormGroup = this.formBuilder.group({
    TransDate: [
      null,
      customValidators.dateTypeStringValidator({
        required: true,
      }),
    ],
    FirstInstDate: [
      null,
      customValidators.dateTypeStringValidator({
        required: true,
      }),
    ],
  });
  installmentsFormArray: FormArray = this.formBuilder.array([]);
  //#endregion

  constructor(
    private loanService: LoansService,
    private installmentService: InstallmentsService,
    private referenceService: ReferencesService,
    private datePipe: DatePipe,
    private bankService: BankService,
    private alertService: AlertService,
    public inputMaskingService: InputMaskingService,
    private formBuilder: FormBuilder,
    private userService: UserService,
    private cdref: ChangeDetectorRef,
    private env: EnvService,
    private http: HttpClient,
    private reportingService: ReportingService,
    private authService: MohassilAuthService,
    private pdfViewerService: PdfViewerService
  ) {}

  //#region Initiallize
  ngAfterContentChecked(): void {
    this.cdref.detectChanges();
  }
  async ngOnInit() {
    this.pageTypeAccessRights = await this.authService.getAccessRights();
    if (
      this.pageTypeAccessRights.filter((x) => x.window_code == "5656").length >
      0
    ) {
      this.FreeRescheduleAccess = true;
    }
    this.rescheduleOptions =
      await this.referenceService.GetCalculateInterestOptions();
    this.rescheduleBanks = await this.bankService.getRescheduleBanks();
    this.periodStartDate = new Date(
      (await Preferences.get({ key: "periodStartDate" })).value
    );
    this.periodEndDate = new Date(
      (await Preferences.get({ key: "periodEndDate" })).value
    );

    if (
      !localStorage.getItem("periodStartDate") ||
      !localStorage.getItem("periodEndDate")
    ) {
      this.userBranchInfo = await this.userService.getUserBranchInfo();
      if (this.userBranchInfo) {
        this.periodStartDate = new Date(this.userBranchInfo.period_start_date);
        this.periodEndDate = new Date(this.userBranchInfo.period_end_date);
        await Preferences.set({
          key: "periodStartDate",
          value: this.datePipe.transform(
            this.userBranchInfo.period_start_date,
            "yyyy-MM-dd"
          ),
        });
        await Preferences.set({
          key: "periodEndDate",
          value: this.datePipe.transform(
            this.userBranchInfo.period_end_date,
            "yyyy-MM-dd"
          ),
        });
      }
    }
    if (this.periodStartDate.toString() === this.periodEndDate.toString()) {
      this.TransDateDisabled = true;
    }
    this.TransDatePickerOptions = {
      minDate: this.periodStartDate,
      maxDate: this.periodEndDate,
    };
  }
  //#endregion

  //#region Select Methods
  async clientSelected(event: SearchResult) {
    this.showLoader = true;
    this.ClientloanList = await this.loanService
      .getLoanInfoByClientKey(event.client_key)
      .toPromise();
    if (this.ClientloanList) {
      this.showLoader = false;
      this.isSearching = false;
      this.loanGridView = true;
    }
  }
  backToSearch() {
    this.isSearching = true;
    this.loanGridView = false;
    this.RescheduleView = false;
    this.ClientloanList = null;
    this.selectedLoan = null;
    this.installmentsInfo = null;
    this.newInstallmentsInfo = null;
    this.rescheduleForm.reset();
    this.FreeReschedule = false;
    this.ChequesPrintCheckbox = false;
    this.ChequesPrintCheckbox = false;
    this.accordionGroupValue = "first";
  }
  async loanSelected(loan: LoanInfoData) {
    this.showLoader = true;
    this.selectedLoan = loan;
    this.loanNo = loan.loan_no;
    this.loanIntRt = loan.loan_int_rt;
    this.installmentsInfo = await this.installmentService
      .GetInstallmentsInfoByLoanKey(this.selectedLoan.loan_key)
      .toPromise();
    if (this.installmentsInfo) {
      this.showLoader = false;
      this.RescheduleView = true;
      this.loanGridView = false;
      this.FirstInstDatePickerOptions = {
        minDate: new Date(this.selectedLoan.loan_last_trans_date),
      };
    }
  }
  //#endregion

  //#region Rescheduling
  onSelectChanged(ev: any) {
    this.calcFeesFrom = Number(ev.detail.value);
    switch (this.calcFeesFrom) {
      case 0:
        this.instIntCheckboxDisable = false;
        this.gracePrdInstCheckboxDisable = true;
        this.gracePrdInstCheckbox = false;
        break;
      case 1:
        this.instIntCheckboxDisable = false;
        this.gracePrdInstCheckboxDisable = false;
        break;
      case 2:
        this.instIntCheckboxDisable = true;
        this.instIntCheckbox = false;
        this.gracePrdInstCheckboxDisable = false;
        break;
    }
  }
  savePrevValues() {
    this.prevLoanNo = this.loanNo;
    this.prevGracePeriod = this.gracePeriod;
    this.prevLoanIntRt = this.loanIntRt;
    this.prevTransDate = this.rescheduleForm.controls.TransDate.value;
    this.prevFirstInstDate = this.rescheduleForm.controls.FirstInstDate.value;
  }
  checkForPrevValues() {
    if (
      this.loanNo != this.prevLoanNo ||
      this.gracePeriod != this.prevGracePeriod ||
      this.loanIntRt != this.prevLoanIntRt ||
      this.rescheduleForm.controls.TransDate.value != this.prevTransDate ||
      this.rescheduleForm.controls.FirstInstDate.value != this.prevFirstInstDate
    ) {
      this.rescheduleLoan();
    }
  }
  async changeGracePeriod(i: number) {
    const input = Number(i);
    const loan_last_trans_date = this.selectedLoan.loan_last_trans_date;
    const loan_date = this.selectedLoan.loan_date;
    const period_length = this.selectedLoan.period_length;
    const period_type = this.selectedLoan.period_type;
    let first_pay_date = new Date(loan_last_trans_date);
    if (this.calcFeesFrom === 1) {
      if (period_type === 1) {
        first_pay_date.setMonth(
          first_pay_date.getMonth() + period_length * (input + 1)
        );
      } else if (period_type === 3) {
        first_pay_date.setDate(
          first_pay_date.getDate() + period_length * (input + 1)
        );
      }
    } else if (this.calcFeesFrom === 0) {
      let calculatedFirstInstDate = new Date(loan_date);
      if (period_type === 1) {
        calculatedFirstInstDate.setMonth(
          calculatedFirstInstDate.getMonth() + period_length * (input + 1)
        );
      } else if (period_type === 3) {
        calculatedFirstInstDate.setDate(
          calculatedFirstInstDate.getDate() + period_length * (input + 1)
        );
      }
      if (
        this.calculateDateDiff(loan_last_trans_date, calculatedFirstInstDate) >
        0
      ) {
        first_pay_date = calculatedFirstInstDate;
      } else {
        await this.alertService.showAlertError(
          "فتره السماح المدخله ينتج عنها تاريخ استحقاق اول قسط يسبق تاريخ الجدوله",
          false
        );
        this.gracePeriod = this.FixedGracePeriod;
        return;
      }
    } else if (this.calcFeesFrom === 2) {
      let calculatedFirstInstDate = new Date(loan_last_trans_date);
      if (period_type === 1) {
        calculatedFirstInstDate.setMonth(
          calculatedFirstInstDate.getMonth() + period_length * (input + 1)
        );
      } else if (period_type === 3) {
        calculatedFirstInstDate.setDate(
          calculatedFirstInstDate.getDate() + period_length * (input + 1)
        );
      }
      if (
        this.calculateDateDiff(loan_last_trans_date, calculatedFirstInstDate) >
        0
      ) {
        first_pay_date = calculatedFirstInstDate;
      } else {
        await this.alertService.showAlertError(
          "فتره السماح المدخله ينتج عنها تاريخ استحقاق اول قسط يسبق تاريخ الجدوله",
          false
        );
        this.gracePeriod = this.FixedGracePeriod;
        return;
      }
    }
    this.rescheduleForm.patchValue({
      FirstInstDate: this.datePipe.transform(first_pay_date, "yyyy-MM-dd"),
    });
    this.checkForPrevValues();
  }
  changeTransDate(ev: any) {
    if (this.rescheduleForm.valid) {
      this.rescheduleForm.patchValue({
        TransDate: ev,
      });
      this.checkForPrevValues();
    }
  }
  changeFirstIntDate(ev: any) {
    if (this.rescheduleForm.valid) {
      this.rescheduleForm.patchValue({
        FirstInstDate: ev,
      });
      this.checkForPrevValues();
    }
  }
  async rescheduleLoan() {
    this.checkDatesInput = true;
    this.FreeReschedule = false;
    this.installmentsFormArray.clear();
    if (this.newInstallmentsInfo && this.loanNo <= this.selectedLoan.loan_no) {
      this.alertService.showAlertError(
        "عدد الأقساط يجب أن يكون أكبر من أقساط الجدول الحالي و أقل من 1000 قسط",
        false
      );
      this.loanNo = this.newInstallmentsInfo.length;
      return;
    }
    if (this.newInstallmentsInfo && !this.rescheduleForm.valid) {
      return;
    }
    this.showLoader = true;
    this.rescheduleRequest = {
      loan_key: this.selectedLoan.loan_key,
      start_date: this.datePipe.transform(
        this.selectedLoan.loan_date,
        "yyyy-MM-dd"
      ),
      end_date: this.datePipe.transform(
        this.rescheduleForm.controls.TransDate.value ?? this.todayDate,
        "yyyy-MM-dd"
      ),
      calc_fees_from: this.calcFeesFrom,
      fees_rate: this.loanIntRt,
      tot_inst_no: this.newInstallmentsInfo ? this.loanNo : 0,
      first_mat_date: this.datePipe.transform(
        this.rescheduleForm.controls.FirstInstDate.value ?? this.nullDate,
        "yyyy-MM-dd"
      ),
      grace_prd_inst: this.gracePrdInstCheckbox ? 1 : 0,
      prev_inst_int: this.instIntCheckbox ? 1 : 0,
    };
    this.newInstallmentsInfo = await this.loanService
      .TestLoanReschedule(this.rescheduleRequest)
      .toPromise();
    this.newInstallmentsInfo.forEach((installment) => {
      this.addInstallmentForm(installment);
      installment.inst_status_date = this.datePipe.transform(
        installment.inst_status_date,
        "yyyy-MM-dd"
      );
    });
    this.loanNo = this.newInstallmentsInfo.length;
    this.gracePeriod =
      this.calcFeesFrom !== 1
        ? this.newInstallmentsInfo[0].grace_period
        : this.gracePeriod;
    const matchingInstallment = this.newInstallmentsInfo.find(
      (installment) =>
        [1, 2, 4].includes(installment.inst_status) &&
        installment.inst_am - installment.inst_int > 0
    );
    if (matchingInstallment) {
      this.rescheduleForm.patchValue({
        FirstInstDate: this.datePipe.transform(
          matchingInstallment.inst_mat_date,
          "yyyy-MM-dd"
        ),
      });
    }
    this.newInstallmentsInfo = this.newInstallmentsInfo.map((x) => {
      const match = this.installmentsInfo.find(
        (y) => y.inst_serial === x.inst_serial
      );
      return match ? { ...x, uuc: match.uuc } : x;
    });
    this.FixedLoanNo = this.newInstallmentsInfo.length;
    this.FixedloanIntRt = this.loanIntRt;
    this.FixedGracePeriod = this.newInstallmentsInfo[0].grace_period;
    this.FixedFirstIntDate = this.datePipe
      .transform(this.rescheduleForm.controls.FirstInstDate.value, "yyyy-MM-dd")
      .toString();
    this.FixedTransDate = this.datePipe
      .transform(
        this.rescheduleForm.controls.TransDate.value ?? this.todayDate,
        "yyyy-MM-dd"
      )
      .toString();
    this.instIntCheckboxDisable = true;
    this.rescheduleOptionDisable = true;
    this.gracePrdInstCheckboxDisable = true;
    this.accordionGroupValue = "second";
    this.showLoader = false;
  }
  changingInstBank(i: number) {
    this.rescheduleBanks.filter((x) => {
      if (x.bank_code === this.newInstallmentsInfo[i].inst_org_bank) {
        this.newInstallmentsInfo[i].inst_org_bank_name = x.bank_name;
      }
    });
  }
  cancelRescheduleLoan() {
    this.newInstallmentsInfo = null;
    this.rescheduleForm.reset();
    this.accordionGroupValue = "first";
    this.rescheduleOptionDisable = false;
    switch (this.calcFeesFrom) {
      case 0:
        this.instIntCheckboxDisable = false;
        this.gracePrdInstCheckboxDisable = true;
        this.gracePrdInstCheckbox = false;
        break;
      case 1:
        this.instIntCheckboxDisable = false;
        this.gracePrdInstCheckboxDisable = false;
        break;
      case 2:
        this.instIntCheckboxDisable = true;
        this.instIntCheckbox = false;
        this.gracePrdInstCheckboxDisable = false;
        break;
    }
  }
  //#endregion

  //#region Submit
  async saveReschedule() {
    this.installmentsFormArray.controls.forEach(
      (group: FormGroup, index: number) => {
        const instMatDate = group.get("instMatDate")?.value;
        if (this.newInstallmentsInfo[index]) {
          this.newInstallmentsInfo[index].inst_mat_date = instMatDate;
        }
      }
    );
    let errors = this.validateFreeFields();
    if (errors.length > 0) {
      this.alertService.showAlertError(
        `<br>حدث خطأ عند الجدولة </br>` + `${errors}`,
        false
      );
      return;
    } else if (this.isEveryFormGroupValid()) {
      if (await this.alertService.SaveAlert("هل انت متاكد من جدولة القرض؟")) {
        this.showLoader = true;
        let input = {
          loan_int_rt: this.FixedloanIntRt,
          loan_uuc: this.selectedLoan.uuc,
          loan_notes: this.selectedLoan.loan_notes,
          installments: this.newInstallmentsInfo,
        };
        this.http
          .post(this.env.API_URL + `api/Loan/SaveLoanReschedule`, input)
          .subscribe({
            next: async () => {
              this.showLoader = false;
              if (this.ChequesPrintCheckbox) {
                this.cancelRescheduleLoan();
                this.selectedLoan.loan_no = this.FixedLoanNo;
                this.selectedLoan.loan_int_rt = this.FixedloanIntRt;
                this.selectedLoan.loan_last_trans_date = new Date(
                  this.FixedTransDate
                );
                this.ClientloanList = await this.loanService
                  .getLoanInfoByClientKey(Number(this.selectedLoan.client_key))
                  .toPromise();
                this.ClientloanList.filter((x) => {
                  if (x.loan_key === this.selectedLoan.loan_key) {
                    this.selectedLoan = x;
                  }
                });
                this.installmentsInfo = await this.installmentService
                  .GetInstallmentsInfoByLoanKey(this.selectedLoan.loan_key)
                  .toPromise();
                await this.printRescheduleCheques();
                this.alertService.showAlertConfirm(
                  "تمت جدولة القرض بنجاح",
                  false
                );
              } else {
                this.alertService.showAlertConfirm(
                  "تمت جدولة القرض بنجاح",
                  true
                );
              }
            },
            error: async (err) => {
              await this.alertService.showAlertError(err.error, false);
              this.showLoader = false;
            },
          });
      }
    }
  }
  //#endregion

  //#region Free Reschedule
  AdjustInstallments(event: Event) {
    event.stopPropagation();
    this.FreeReschedule = true;
    this.checkInstMatDateInput = true;
  }
  validateFreeFields(): string {
    let errors: string = "";
    this.newInstallmentsInfo.forEach((installment, i) => {
      if (!installment.inst_am) {
        errors += `<br>(${installment.inst_serial}) : قيمه القسط غير سليمه </br>`;
      }
      if (!installment.inst_int) {
        errors += `<br>(${installment.inst_serial}) : قيمة المصاريف غير سليمه </br>`;
      }
      if (!installment.inst_mat_date) {
        errors += `<br>(${installment.inst_serial}) : تاريخ الاستحقاق غير سليم </br>`;
      }
      if (Number(installment.inst_am) <= 0) {
        errors += `<br>(${installment.inst_serial}) : قيمة القسط لا يجب أن تكون أقل من أو تساوي صفر </br>`;
      }
      if (
        Number(installment.inst_am) < Number(installment.inst_int) &&
        Number(installment.inst_am) > 0
      ) {
        console.log(
          installment.inst_serial,
          installment.inst_am,
          installment.inst_int
        );
        errors += `<br>(${installment.inst_serial}) : قيمة القسط يجب أن تكون أكبر من قيمة المصاريف </br>`;
      }
      if (
        i === this.installmentsInfo.length &&
        this.calculateDateDiff(this.FixedTransDate, installment.inst_mat_date) <
          0
      ) {
        errors += `<br>(${installment.inst_serial}) : التاريخ يجب أن لا يقل عن تاريخ الحركة </br>`;
      }
      if (i > 0) {
        let prevInstMatDate = this.newInstallmentsInfo[i - 1].inst_mat_date;
        if (
          i > this.installmentsInfo.length &&
          this.calculateDateDiff(prevInstMatDate, installment.inst_mat_date) < 0
        ) {
          errors += `<br>(${installment.inst_serial}) : التاريخ يجب أن لا يقل عن تاريخ آخر سداد </br>`;
        }
      }
    });
    if (errors.length === 0) {
      let tot_resc_insts = this.installmentsInfo.reduce((sum, inst) => {
        if ([1, 2, 4].includes(inst.inst_status)) {
          return sum + (inst.inst_am - inst.inst_int);
        }
        return sum;
      }, 0);
      let tot_new_insts = this.newInstallmentsInfo.reduce((sum, inst) => {
        if ([1, 2].includes(inst.inst_status)) {
          return sum + (inst.inst_am - inst.inst_int);
        }
        return sum;
      }, 0);
      if (
        this.calculateDateDiff(this.FixedFirstIntDate, this.FixedTransDate) > 0
      ) {
        errors += `(*) : التاريخ يجب أن لا يقل عن تاريخ اول تاريخ إستحقاق \n`;
      }
      if (tot_resc_insts != tot_new_insts) {
        errors += `(*) : أصل المبلغ يجب أن لا يتغير عن الأصل الغير مسدد \n`;
      }
    }
    return errors;
  }
  //#endregion

  //#region Reports
  async printReschedulePreviewReport(event: Event) {
    if (this.isEveryFormGroupValid()) {
      let rescheduleReport: string = null;
      this.showLoader = true;
      event.stopPropagation();
      this.installmentsFormArray.controls.forEach(
        (group: FormGroup, index: number) => {
          const instMatDate = group.get("instMatDate")?.value;
          if (this.newInstallmentsInfo[index]) {
            this.newInstallmentsInfo[index].inst_mat_date = instMatDate;
          }
        }
      );
      let token = await this.authService.getAccessToken();
      token = token.replace("-", "+").replace("_", "/");
      const claims = JSON.parse(atobSafe(token.split(".")[1]));
      let date: Date = new Date();
      let reportParameter: Array<{ key: string; value: string }> = [
        { key: "client_name", value: this.selectedLoan.client_name.toString() },
        {
          key: "loan_date",
          value: this.datePipe
            .transform(this.selectedLoan.loan_date, "yyyy-MM-dd")
            .toString(),
        },
        { key: "loan_am", value: this.selectedLoan.loan_am.toString() },
        {
          key: "currency_name",
          value: this.selectedLoan.currency_name.toString(),
        },
        { key: "loan_vouch", value: this.selectedLoan.loan_vouch.toString() },
        { key: "loan_no", value: this.selectedLoan.loan_no.toString() },
        { key: "loan_gp", value: this.gracePeriod.toString() },
        {
          key: "period_length",
          value: this.selectedLoan.period_length.toString(),
        },
        {
          key: "period_desc",
          value: this.selectedLoan.period_type_desc.toString(),
        },
        { key: "bank_name", value: this.selectedLoan.bank_name.toString() },
        { key: "loan_int_rt", value: this.FixedloanIntRt.toString() },
        {
          key: "loan_int_rt_desc",
          value: this.selectedLoan.loan_int_type_desc.toString(),
        },
        {
          key: "officer_name",
          value: this.selectedLoan.officer_name.toString(),
        },
        {
          key: "loan_int_rt_2",
          value: this.selectedLoan.loan_int_rt_2
            ? this.selectedLoan.loan_int_rt_2.toString()
            : "0",
        },
        {
          key: "loan_int_rt2_desc",
          value: this.selectedLoan.loan_int_type_2_desc.toString(),
        },
        {
          key: "loan_int_deduct2_desc",
          value: this.selectedLoan.loan_int_2_deduct_desc.toString(),
        },
        {
          key: "loan_status_desc",
          value: this.selectedLoan.loan_status_desc.toString(),
        },
        {
          key: "loan_cond_desc",
          value: this.selectedLoan.loan_cond_desc.toString(),
        },
        {
          key: "first_inst",
          value: this.FixedFirstIntDate,
        },
        {
          key: "loan_last_trans_date",
          value: this.selectedLoan.loan_last_trans_date.toString(),
        },
        { key: "org_name", value: this.selectedLoan.org_code.toString() },
        { key: "branch_name", value: this.selectedLoan.branch_name.toString() },
        { key: "user_name", value: claims.user_name.toString() },
        {
          key: "execution_time",
          value: this.datePipe.transform(date, "yyyy-MM-dd").toString(),
        },
      ];
      rescheduleReport =
        await this.reportingService.getLoanReschedulePreviewReport(
          reportParameter,
          this.newInstallmentsInfo
        );
      if (rescheduleReport) {
        this.pdfViewerService.viewPdf(
          rescheduleReport,
          `تقرير الجدولة قبل الحفظ  ${this.selectedLoan.client_name}`
        );
      }
      this.showLoader = false;
    }
  }

  async printRescheduleCheques() {
    this.showLoader = true;
    let chequesReprot: string;
    let reportName: string =
      "web_" + this.selectedLoan.org_code.toString() + "_collateral_print";
    let reportParameters: Array<{ key: string; value: string }> = [
      {
        key: "@cur_loan_key",
        value: this.selectedLoan.loan_key.toString(),
      },
      {
        key: "@inst_status",
        value: this.selectedLoan.loan_status.toString(),
      },
    ];
    await this.reportingService
      .getReport(reportName, reportParameters)
      .then((x) => {
        chequesReprot = x;
        if (chequesReprot) {
          this.pdfViewerService.viewPdf(
            chequesReprot,
            `شيكات ${this.selectedLoan.client_name}`
          );
        }
      })
      .finally(() => {
        this.showLoader = false;
      });
  }
  //#endregion

  //#region Dates Handling
  addInstallmentForm(installment: any): void {
    const installmentForm = this.formBuilder.group({
      instMatDate: [
        this.datePipe.transform(
          new Date(installment.inst_mat_date),
          "yyyy-MM-dd"
        ),
        customValidators.dateTypeStringValidator({
          required: true,
        }),
      ],
    });

    this.installmentsFormArray.push(installmentForm);
  }
  getFormGroup(i: number): FormGroup {
    return this.installmentsFormArray.at(i) as FormGroup;
  }
  setInstMatDate(index: number) {
    if (this.installmentsFormArray.at(index).valid) {
      this.newInstallmentsInfo[index].inst_mat_date = this.datePipe
        .transform(
          new Date(
            this.installmentsFormArray.at(index).get("instMatDate").value
          ),
          "yyyy-MM-dd"
        )
        .toString();
    }
  }
  isEveryFormGroupValid(): boolean {
    return this.installmentsFormArray.controls.every(
      (group: FormGroup) => group.valid
    );
  }
  calculateDateDiff(date1: string | Date, date2: string | Date): number {
    const d1 = new Date(date1);
    const d2 = new Date(date2);
    const timeDiff = d2.getTime() - d1.getTime();
    const diffDays = timeDiff / (1000 * 3600 * 24);
    return diffDays;
  }
  //#endregion
}
